def stress_test(income, savings, expenses, rate=0.20):
    total_exp = sum(a for _,a,_ in expenses)
    variable = [(c,a,t) for c,a,t in expenses if t=='variable']
    fixed    = [(c,a,t) for c,a,t in expenses if t=='fixed']
    stressed = total_exp + sum(a*rate for _,a,t in expenses
                               if t=='variable')
    deficit  = (stressed + savings) - income
    cut_list = sorted(variable, key=lambda x: -x[1]) + \
               sorted(fixed,    key=lambda x: -x[1])
    return deficit, cut_list

def compound(savings, rate=0.06, years=10):
    monthly = savings
    fv = sum(monthly*(1+rate/12)**(12*(years-t/12))
             for t in range(12*years))
    return round(fv, 2)
